/** Point GeoJSON for governorate labels (centroids) */
export const GOV_LABELS_GEOJSON: FeatureCollection<Point, { nameEn: string }> = {
  type: "FeatureCollection",
  features: GOVERNORATES.map((g) => ({
    type: "Feature" as const,
    properties: { nameEn: g.nameEn },
    geometry: { type: "Point" as const, coordinates: [g.lng, g.lat] },
  })),
};

/** Point GeoJSON for subgovernorate labels (centroids) */
export const SUBGOV_LABELS_GEOJSON: FeatureCollection<Point, { nameEn: string }> = {
  type: "FeatureCollection",
  features: SUBGOVERNORATES.map((s) => ({
    type: "Feature" as const,
    properties: { nameEn: s.nameEn },
    geometry: { type: "Point" as const, coordinates: [s.lng, s.lat] },
  })),
};

